parameters.jsCode:
const email = $json.raw_email || '';

function extract(regex) {
const match = email.match(regex);
return match ? match[1].trim() : null;
}

// Extraction des champs principaux
const case_number = extract(/ID CASE\s*:\s*(.*?)\s+Client\s*:/is);

const customer_name = extract(
/Client\s*:\s*(.*?)\s+Téléphone\s*:/is
);

let customer_phone = extract(
  /Téléphone\s*:\s*(.*?)\s+Accès réseau\s*:/is
);

// Si téléphone vide => récupérer Contact dans commentaire
if (!customer_phone || customer_phone.trim() === '') {

  const contactMatch = email.match(
    /Contact\s*:\s*(\d{10})/i
  );

  if (contactMatch) {
    customer_phone = contactMatch[1];
  }
}
const network_access = extract(
/Accès réseau\s*:\s*(.*?)\s+Activités de service\s*:/is
);

const service_activity = extract(
/Activités de service\s*:\s*(.*?)\s+Type de problème\s*:/is
);

const problem_type = extract(
/Type de problème\s*:\s*(.*?)\s+Description\s*:/is
);

let description_text = extract(
/Description\s*:\s*(.*?)\s+Commentaire\s*:/is
);

// Nettoyage description
description_text = (description_text || '').trim();

if (
description_text === "'" ||
description_text === '"' ||
description_text === "''"
) {
description_text = '';
}

const comment_text = extract(
/Commentaire\s*:\s*(.*?)\s+Id connexion\s*:/is
);

const internet_login = extract(
/Login Internet\s*:\s*(.*)/is
);

// Adresse Installation
let full_address = extract(
/Adresse Installation\s*:\s*(.*?)\s+Login Internet\s*:/is
);

// Si Adresse Installation vide => chercher dans commentaire
if (!full_address && comment_text) {
const addressMatch = comment_text.match(
/Adresse\s*:\s*(.*?)(?:Description de l’incident|Date d’incident|GPON|Voyants|INJECTION|$)/is
);

if (addressMatch) {
full_address = addressMatch[1].trim();
}
}

// Liste des zones
const zones = [
'GIRONDE',
'MAARIF',
'RACINE',
'BOURGOGNE',
'BACKHOU',
'BEAUSEJOUR',
'GAUTHIER',
'ALSACE',
'PALMIER',
'DERB GHALEF',
'VAL FLEURI',
'CIT PLATEAU',
'BELVEDERE',
'BIADA',
'AIN BORJA',
'CENTRE VILLE',
'HOPITAUX',
'MOUAHIDINE',
'ROCHES NOIRES',
'PALESTINE',
'HAY MOHAMMADI',
'CIL',
'CIL POTO',
'TETOUAN',
'MEDINA',
'BURGER',
'ABOUJARRAH'
];

// Détection zone
let local_area = null;

const searchText = (
email +
' ' +
(full_address || '') +
' ' +
(comment_text || '')
).toUpperCase();

for (const zone of zones) {
if (searchText.includes(zone)) {
local_area = zone;
break;
}
}

// Détection DOWN (uniquement incidents collectifs)
let case_type = 'NORMAL';

if (
searchText.includes('CLIENTS DOWN') ||
searchText.includes('INCIDENT DOWN') ||
searchText.includes('INCIDENT COLLECTIF') ||
searchText.includes('PANNE COLLECTIVE') ||
searchText.includes('PLUSIEURS CLIENTS')
) {
case_type = 'DOWN';
}

// Fallback
if (!local_area) {
local_area = 'UNKNOWN';
}

return [
{
json: {
case_number,
case_type,
customer_name,
customer_phone,
network_access,
service_activity,
problem_type,
description_text,
comment_text,
internet_login,
full_address,
local_area
}
}
];

